sys_script_email.script:
(function runMailScript( /* GlideRecord */ current, /* TemplatePrinter */ template,
    /* Optional EmailOutbound */
    email, /* Optional GlideRecord */ email_action,
    /* Optional GlideRecord */
    event) {

    var CLOSE_CODE_MAP = {
        successful: 'Maintenance was successful',
        successful_issues: 'Maintenance was successful',
        partially_implemented: 'Maintenance was partially completed',
        unsuccessful: 'Maintenance was unsuccessful',
        unsuccessful_dueto3rdParty: 'Maintenance was unsuccessful',
        unable_to_start: 'Maintenance was unsuccessful'
    }
    var change = current.u_related_ticket.number;
    var closeCode = current.u_related_ticket.close_code;
	closeCode = closeCode.trim().replace(/\s+/g, '');
    var location = current.getDisplayValue('u_locations');
    var subject = current.short_description;
    var statusText = CLOSE_CODE_MAP[closeCode];
    var subjectLine = 'Window Closed Maintenance - ' + statusText + ' - at ' + location + ' - ' + subject + ' - ' + change;
    email.setSubject(subjectLine);

})(current, template, email, email_action, event);
